var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"어때? 회사랑 연락은 돼?","JPN":"どう？　会社に連絡はついた？","ENG":"Well? Any luck getting in touch with your company?","TWN":"怎麼樣？能連絡到公司嗎？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 아까부터 계속 먹통이야.","JPN":"ううん、さっきからずっと連絡がつかない。","ENG":"Nope. Their comms seem to be down.","TWN":"不行，從剛才開始就一直無法通信。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"회, 회사뿐만 아니라 다른 곳에도 연락이 안 돼요.","JPN":"か、会社だけじゃなくて、他所にも連絡がつきません。","ENG":"I-it's not just the company. It's everywhere else, too.","TWN":"不、不只有公司，就連其他地方也連絡不上。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"토, 통신망에 문제가 생겼나 봐요.","JPN":"ね、ネットワークに何か問題が起きたみたいです。","ENG":"There must be a problem with the communication network.","TWN":"似、似乎是通信網路出了問題。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"이상하네....... 지금쯤이면 다른 태스크포스도 왔어야 할 텐데.......","JPN":"おかしいな……他のタスクフォースカンパニーもそろそろ着くころだと思うけど……","ENG":"That's weird... The other TASKFORCE companies should have arrived by now...","TWN":"太奇怪了……其他特遣勢力也差不多該來了啊……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"네. 미, 민간인 거주구는 관리국 위성이 항상 감시하고 있을 텐데요.......","JPN":"はい、民間人の居住区は管理局の衛星が常に監視しているはずですが……","ENG":"You're right. The Administration's satellites are always monitoring the civilian area...","TWN":"是啊，平、平民居住區平時就有管理局的衛星監視著的……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"어째서 아무 소식이 없는 걸까요......?","JPN":"どうして何の連絡も無いのでしょうか……？","ENG":"So how come we haven't heard anything from them?","TWN":"怎麼會一點消息都沒有？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......이유가 뭐든, 당장 외부에서 도움을 기대할 순 없겠어.","JPN":"……理由が何であれ、外部からの支援は期待できないな。","ENG":"Whatever the reason is, I don't think we'll be getting any outside help.","TWN":"……不管是什麼原因，看來我們都不用指望外部支援了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"흑흑...... 어째서 항상 필요할 땐 아무도 없는 걸까.......","JPN":"ううっ……どうして必要な時に限って誰もいないんでしょう……","ENG":"*Sob* How come nobody there to help when you need them the most...","TWN":"哭哭……為什麼我有難時總是誰都不在呢……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이제 다 틀렸나 봐요.","JPN":"もう、すべてがおしまいです。","ENG":"Oh, we're done for!","TWN":"現在全完了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저흰 이 차가운 길바닥에서 쓸쓸하게 죽어 버릴 거예요.......","JPN":"ヒミコたちはこの冷たいコンクリートの上でさみしく息絶えてしまうんですぅ……","ENG":"We're all going to die here...","TWN":"我們就要在冰冷的路上孤獨地死去了……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"다들 포기하기엔 일러!","JPN":"みんな、諦めるのはまだ早いよ！","ENG":"It's too soon to give up!","TWN":"大家要放棄還太早了！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"밖에서 안으로 지원이 없으면 우리가 안에서 밖으로 나가면 돼!","JPN":"外からの支援がないなら、こっちから外に出ていけばいいんだよ！","ENG":"If nobody's coming to help, we'll just have to take the fight to them!","TWN":"既然沒有外援進來，那我們自己出去就行了！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"......네?","JPN":"……はい？","ENG":"...Sorry?","TWN":"……咦？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"그렇잖아? 우리가 침식체들을 유인해서 도시 밖으로 나가는 거야!","JPN":"だって、そうでしょ？　みんなで侵食体をおびき寄せて郊外に連れていこうよ！","ENG":"You know what I mean? We can lure the Corrupted Objects away from the city!","TWN":"不是嗎？我們把侵蝕體引到城市外面就好啦！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"그럼 다른 도시들도 상황을 알아차리고 지원 병력을 보내 줄 거야!","JPN":"そうすれば、他の街も状況を理解して支援を送ってくれるはず！","ENG":"That way, the other cities will realize what's going on and send reinforcements!","TWN":"這樣其他城市就會知道這裡的情況，向這裡派出援兵了！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저 많은 침식체들을 몰고 나가자는 거예요?","JPN":"あのたくさんいる侵食体を連れて行くんですか？","ENG":"You want to herd all those Corrupted Objects out of here?","TWN":"妳要把這麼多的侵蝕體引出城市？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"무, 무서워.......","JPN":"こ、怖いですぅ……","ENG":"I-I'm scared...","TWN":"好、好可怕……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"너무 위험해. 에이미, 이건 성급하게 정할 일이 아닌 것 같아요.","JPN":"それは危険すぎます。エイミー、むやみに動くべきじゃないですよ。","ENG":"It's too dangerous. I think we need to think through this, Amy.","TWN":"太危險了，艾米，還是不要這麼倉促地做決定比較好。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"우리 조금만 더 고민해 보죠.","JPN":"もう少しだけ、みんなで考えてみましょう。","ENG":"Let's sit down and think for a moment.","TWN":"我們再稍微考慮一下吧。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"......얼마나?","JPN":"……どれくらい？","ENG":"...For how long?","TWN":"……妳要考慮多久？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"한 사흘 정도......?","JPN":"そうですね、あと3日くらい……？","ENG":"About three days...?","TWN":"一到三天？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"기각.","JPN":"却下。","ENG":"Request denied.","TWN":"駁回。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"사흘 후면 이 도시에 남아 있는 건 황무지밖에 없을걸?","JPN":"3日後って、この街が荒地になっちゃってるよ？","ENG":"This city will be reduced to a wasteland in three days!","TWN":"三天後，這座城市就只剩下廢墟了吧？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"시간을 더 끌면....... 병원도 위험해질 거라고.","JPN":"時間をかければかけるほど……病院の状況も悪化するはずだよ。","ENG":"If we waste any more time... The hospital will be in danger.","TWN":"再拖下去的話……醫院也會很危險的。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"미나랑 소빈이도...... 할 거지?","JPN":"ミナちゃんとコハルちゃんも……いっしょに来てくれるよね？","ENG":"Mina and Sobin... Will you help?","TWN":"米娜和素蘋……你們也會來的吧？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......하아, 젠장.","JPN":"……はああ、もうっ。","ENG":"Ugh... Screw it.","TWN":"……唉，該死。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알았어. 알았으니까, 노닥거리지 말고 얼른 움직이자.","JPN":"わかった、わかったから、こうしてないで早く動こう。","ENG":"Fine. So let's stop fooling around here and get moving.","TWN":"好啦，好啦。不要再打情罵俏的，快走吧。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아앗! 토론도 안 거치고 일을 진행하겠단 건가요?!","JPN":"えっ！　会議もしないで動くと言ってるんですか！？","ENG":"What?! You're going to proceed without even discussing about it?","TWN":"咦！妳沒跟我們討論就決定要走了嗎？！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이 폭군! 독재자!","JPN":"この暴君！　独裁者！","ENG":"You're a tyrant! Dictator!","TWN":"妳這個暴君！獨裁者！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"안 도울 거면 너흰 여기 있든지.","JPN":"手伝わないなら、ここに残る？","ENG":"Just wait here if you're not going to help.","TWN":"你們不要我幫忙的話，那就待在這裡好了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"물론 이 주변에 숨어 있던 침식체가 습격해 오면 그건 너희들끼리 알아서 해야겠지만.","JPN":"もちろん、この近くに隠れた侵食体が襲撃してきたときは、そっちで何とかしてよね。","ENG":"But if the Corrupted Objects come this way, you guys are on your own.","TWN":"當然，如果潛藏在四周的侵蝕體襲擊了你們，你們就得自己看著辦了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"안녕히 계세요, 히로세 씨. 전 미나 양을 따라가기로 했어요.","JPN":"さようなら、廣瀬さん。私はミナさんについていきます。","ENG":"Goodbye, Ms. Hirose. I've decided to follow Mina.","TWN":"再見了，廣瀨，我要跟米娜小姐走了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"누구 맘대로 작별 인사예요!? 저도 같이 갈 거라고요!","JPN":"勝手に別れを告げないでください！　秋も行くんですから！","ENG":"Who ever said anything about goodbye? I'm coming with you!","TWN":"妳別擅自告別好嗎！？我也要一起去啊！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"기다려요!!","JPN":"待ってください！！","ENG":"Wait up!","TWN":"等等我啊！！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};